import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import axios from 'axios';
import Navbar from "./components/Navbar";

const cacheBusqueda = {};

function App() {
  // --- ESTADOS DE AUTENTICACIÓN ---
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [authMode, setAuthMode] = useState('login'); 
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [email, setEmail] = useState(''); 
  const [telefono, setTelefono] = useState(''); 
  const [userRole, setUserRole] = useState('vendedor');
  const [nuevoRol, setNuevoRol] = useState('vendedor');

  // --- ESTADOS DE DATOS ---
  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false);

  // --- ESTADOS DE FORMULARIO ---
  const [showForm, setShowForm] = useState(false);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', stock: '', precio_venta: '' });

  // --- ESTADOS DE SEGURIDAD 2FA ---
  const [twoStep, setTwoStep] = useState(false); 
  const [otp, setOtp] = useState(''); 

  const abortControllerRef = useRef(null);

  // 1. CARGA DE DATOS COMPLETA
  const cargarDatos = useCallback(async () => {
    setLoading(true);
    try {
      const [resStats, resProds] = await Promise.all([
        axios.get('http://localhost:5000/api/stats'),
        axios.get('http://localhost:5000/api/productos')
      ]);
      setStats(resStats.data);
      setProductos(resProds.data);
    } catch (error) { console.error("Error cargando:", error); } 
    finally { setLoading(false); }
  }, []);

  useEffect(() => {
    if (isLoggedIn) {
      cargarDatos();
      const interval = setInterval(cargarDatos, 30000);
      return () => clearInterval(interval);
    }
  }, [isLoggedIn, cargarDatos]);

  // 2. BUSQUEDA CON DEBOUNCE
  const ejecutarBusqueda = useCallback(async (texto) => {
    if (texto.trim() === '') { cargarDatos(); return; }
    if (cacheBusqueda[texto]) { setProductos(cacheBusqueda[texto]); return; }
    if (abortControllerRef.current) abortControllerRef.current.abort();
    abortControllerRef.current = new AbortController();
    try {
      const res = await axios.get(`http://localhost:5000/api/productos/buscar?q=${texto}`, { 
        signal: abortControllerRef.current.signal 
      });
      cacheBusqueda[texto] = res.data;
      setProductos(res.data);
    } catch (err) { if (err.name !== 'CanceledError') console.error(err); }
  }, [cargarDatos]);

  const optimizadaBusqueda = useMemo(() => {
    const debounce = (fn, delay) => {
      let timeout;
      return (...args) => { clearTimeout(timeout); timeout = setTimeout(() => fn(...args), delay); };
    };
    return debounce(ejecutarBusqueda, 500);
  }, [ejecutarBusqueda]);

  const handleBusquedaChange = (e) => {
    setBusqueda(e.target.value);
    optimizadaBusqueda(e.target.value);
  };

  // 3. LÓGICA DE ACCESO
  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) {
        setEmail(res.data.email);
        setTwoStep(true); // Activa la pantalla del código
      }
    } catch (e) { alert("Usuario o contraseña incorrectos"); }
  };

  const verificarOTP = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/verify-otp', { usuario, otp });
      if (res.data.success) {
        setUserRole(res.data.rol);
        setIsLoggedIn(true);
      } else { alert("Código incorrecto"); }
    } catch (e) { alert("Error de conexión"); }
  };

  const handleRegister = async () => {
    if (!usuario || !password || !email || !telefono) return alert("Llena todos los campos");
    try {
      const res = await axios.post('http://localhost:5000/api/register', { 
       email, usuario, telefono, clave: password, rol: nuevoRol 
      });
      if (res.data.success) {
        alert("¡Registro exitoso!");
        setAuthMode('login');
      }
    } catch (e) { alert("Error al registrar"); }
  };

  const manejarRecuperacion = async () => {
    try {
        const res = await axios.post('http://localhost:5000/api/recover', { contacto: email || telefono });
        alert(res.data.message);
        setAuthMode('login');
    } catch (e) { alert("No se encontró el usuario"); }
  };

  // 4. LÓGICA DE PRODUCTOS
  const guardarProducto = async () => {
    if(!nuevoProd.nombre || !nuevoProd.stock || !nuevoProd.precio_venta) return alert("Faltan datos");
    try {
      await axios.post('http://localhost:5000/api/productos', {
        nombre: nuevoProd.nombre,
        stock: Number(nuevoProd.stock),
        precio_venta: Number(nuevoProd.precio_venta)
      });
      setShowForm(false);
      cargarDatos();
      setNuevoProd({ nombre: '', stock: '', precio_venta: '' });
    } catch (e) { alert("Error al guardar"); }
  };

  const eliminar = async (id) => {
    if (window.confirm("¿Estás seguro de eliminar este producto?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };

  // --- VISTA DE ACCESO (LOGIN/2FA/RECOVERY) ---
  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#bdc3c7] flex items-center justify-center p-4">
        <div className="bg-[#2d333b] p-10 rounded-[50px] shadow-2xl w-full max-w-sm border border-gray-700">

          {twoStep ? (
            <div className="text-center">
              <i className="fas fa-shield-halved text-[#00c984] text-5xl mb-6"></i>
              <h2 className="text-2xl font-black text-white mb-2 uppercase tracking-tighter">Verificación</h2>
              <p className="text-gray-400 text-[10px] mb-8 uppercase tracking-widest leading-tight">Enviamos un código a:<br/>{email}</p>
              <input 
                maxLength="6"
                placeholder="000000"
                className="w-full bg-[#444c56] text-white text-center text-5xl font-black py-5 rounded-[30px] outline-none mb-8 tracking-[10px]"
                onChange={e => setOtp(e.target.value)}
              />
              <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-5 rounded-[30px] text-xl hover:brightness-110 transition" onClick={verificarOTP}>VERIFICAR</button>
            </div>
          ) : (
            <div className="space-y-4">
              <div className="text-center mb-8">
                <h2 className="text-3xl font-black text-white uppercase tracking-tighter">
                  {authMode === 'login' ? 'Mi Tiendita Pro' : authMode === 'register' ? 'Registro' : 'Recuperar'}
                </h2>
                <div className="w-16 h-1 bg-[#00c984] mx-auto rounded-full mt-2"></div>
              </div>

              {authMode !== 'recovery' && (
                  <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-3xl outline-none" placeholder="Nombre de usuario" onChange={e => setUsuario(e.target.value)} />
              )}

              {authMode === 'register' && (
                <>
                  <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-3xl outline-none" placeholder="Email" onChange={e => setEmail(e.target.value)} />
                  <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-3xl outline-none" placeholder="Teléfono" onChange={e => setTelefono(e.target.value)} />
                  <select className="w-full bg-[#444c56] text-white px-6 py-4 rounded-3xl outline-none" value={nuevoRol} onChange={e => setNuevoRol(e.target.value)}>
                    <option value="vendedor">Vendedor</option>
                    <option value="admin">Administrador</option>
                  </select>
                </>
              )}

              {authMode === 'recovery' && (
                  <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-3xl outline-none" placeholder="Email o Teléfono" onChange={e => setTelefono(e.target.value)} />
              )}

              {authMode !== 'recovery' && (
                <input type="password" underline="false" className="w-full bg-[#444c56] text-white px-6 py-4 rounded-3xl outline-none" placeholder="Contraseña" onChange={e => setPassword(e.target.value)} />
              )}

              <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-5 rounded-[30px] shadow-lg text-lg uppercase transition active:scale-95" 
                onClick={authMode === 'login' ? handleLogin : authMode === 'recovery' ? manejarRecuperacion : handleRegister}>
                {authMode}
              </button>

              <div className="flex justify-between text-[10px] text-gray-400 font-bold uppercase cursor-pointer pt-4 px-2">
                <span className="hover:text-white" onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')}>
                  {authMode === 'login' ? '¿Eres nuevo?' : 'Ya tengo cuenta'}
                </span>
                <span className="hover:text-white" onClick={() => setAuthMode('recovery')}>¿Olvidaste clave?</span>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  // --- VISTA PRINCIPAL (DASHBOARD + INVENTARIO COMPLETO) ---
  return (
    <div className="min-h-screen bg-gray-50 pb-20 md:pb-0">
      <Navbar setView={setView} userRole={userRole} logout={() => setIsLoggedIn(false)} busqueda={busqueda} handleBusquedaChange={handleBusquedaChange} />

      {loading && <div className="h-1.5 w-full bg-[#00c984] fixed top-[80px] z-50 animate-pulse"></div>}

      <main className="max-w-7xl mx-auto p-4 md:p-12">
        {view === "dashboard" ? (
          /* --- DASHBOARD: STATS GIGANTES --- */
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-8 duration-700">
            <h2 className="text-4xl font-black text-[#1e293b] tracking-tighter uppercase italic">Resumen del Sistema</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              <div className="bg-white p-12 border-2 border-slate-100 rounded-[60px] shadow-2xl text-center">
                <p className="text-sm text-slate-400 font-black uppercase mb-4 tracking-widest italic">Stock Total</p>
                <p className="text-9xl font-black text-[#1e293b] leading-none">{stats.total_productos}</p>
              </div>
              <div className="bg-white p-12 border-2 border-slate-100 rounded-[60px] shadow-2xl text-center">
                <p className="text-sm text-red-400 font-black uppercase mb-4 tracking-widest italic">Bajo en Almacén</p>
                <p className="text-9xl font-black text-red-500 leading-none">{stats.bajo_stock}</p>
              </div>
              <div className="bg-white p-12 border-2 border-slate-100 rounded-[60px] shadow-2xl text-center">
                <p className="text-sm text-green-400 font-black uppercase mb-4 tracking-widest italic">Capital Total</p>
                <p className="text-7xl font-black text-green-600 leading-none">${stats.valor_inventario.toLocaleString()}</p>
              </div>
            </div>
          </div>
        ) : (
          /* --- INVENTARIO: TABLA Y FORMULARIO (RESTABLECIDO) --- */
          <div className="space-y-8 animate-in fade-in duration-500">
            <div className="flex justify-between items-center">
                <h2 className="text-4xl font-black text-[#1e293b] uppercase tracking-tighter italic">Gestión de Productos</h2>
                <button onClick={() => setShowForm(!showForm)} className="bg-[#1e293b] text-white px-10 py-4 rounded-3xl font-black text-sm uppercase shadow-xl hover:scale-105 transition">
                    {showForm ? 'Cerrar Panel' : '+ Nuevo Registro'}
                </button>
            </div>

            {showForm && (
              <div className="bg-white p-8 rounded-[40px] border-4 border-dashed border-slate-200 grid grid-cols-1 md:grid-cols-4 gap-4 shadow-inner">
                  <div className="space-y-1">
                    <p className="text-[10px] font-bold text-slate-400 uppercase ml-2">Nombre del producto</p>
                    <input className="w-full p-4 bg-slate-50 rounded-2xl outline-none focus:ring-4 focus:ring-green-400/20 font-bold" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre: e.target.value})} />
                  </div>
                  <div className="space-y-1">
                    <p className="text-[10px] font-bold text-slate-400 uppercase ml-2">Existencia</p>
                    <input className="w-full p-4 bg-slate-50 rounded-2xl outline-none" type="number" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock: e.target.value})} />
                  </div>
                  <div className="space-y-1">
                    <p className="text-[10px] font-bold text-slate-400 uppercase ml-2">Precio de venta</p>
                    <input className="w-full p-4 bg-slate-50 rounded-2xl outline-none" type="number" value={nuevoProd.precio_venta} onChange={e => setNuevoProd({...nuevoProd, precio_venta: e.target.value})} />
                  </div>
                  <div className="flex items-end">
                    <button onClick={guardarProducto} className="w-full bg-[#00c984] text-[#1e293b] font-black rounded-2xl py-4 uppercase shadow-lg shadow-green-500/20 hover:brightness-110">Insertar Producto</button>
                  </div>
              </div>
            )}

            <div className="bg-white border-2 border-slate-100 rounded-[50px] shadow-2xl overflow-hidden overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b border-slate-100">
                      <tr className="text-[11px] font-black uppercase text-slate-400 tracking-widest">
                        <th className="p-8">Detalles del Producto</th>
                        <th className="p-8">Estado de Stock</th>
                        <th className="p-8">Valor Unitario</th>
                        <th className="p-8 text-center">Control de Datos</th>
                      </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50 text-md font-bold text-slate-700 uppercase">
                      {productos.map(p => (
                      <tr key={p.id} className="hover:bg-green-50/50 transition duration-300">
                          <td className="p-8">
                             <span className="text-lg font-black block text-slate-800">{p.nombre}</span>
                             <span className="text-[10px] text-slate-300">ID SISTEMA: #{p.id}</span>
                          </td>
                          <td className="p-8">
                            <span className={`px-5 py-2 rounded-full text-[10px] font-black border-2 ${p.stock < 10 ? 'bg-red-50 text-red-600 border-red-100' : 'bg-green-50 text-green-600 border-green-100'}`}>
                                {p.stock} UNIDADES DISPONIBLES
                            </span>
                          </td>
                          <td className="p-8 text-2xl font-black text-slate-800">${p.precio_venta}</td>
                          <td className="p-8 text-center">
                            <div className="flex justify-center gap-4">
                                <button className="p-4 text-blue-400 hover:bg-blue-50 rounded-3xl transition"><i className="fas fa-edit"></i></button>
                                <button onClick={() => eliminar(p.id)} className="p-4 text-red-400 hover:bg-red-50 rounded-3xl transition"><i className="fas fa-trash"></i></button>
                            </div>
                          </td>
                      </tr>
                      ))}
                  </tbody>
                </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
